  "openapi: 3.0.0\ninfo:\n  title: Music App API\n  version: 1.0.0\n  license:\n    name: Proprietary\n    url: https://music-room/license\n\nservers:\n  - url: http://localhost:54321/functions/v1\n    description: Local Supabase Edge functions\n\n# All endpoints require a Bearer token by default\nsecurity:\n  - bearerAuth: []\n\n########## [TAGS]\ntags:\n  - name: Events\n    description: Routes related to events (listing, details, radar, etc.)\n  - name: Search\n    description: Routes to search tracks, playlists, users, and events.\n  - name: Profile\n    description: Routes related to user profiles and follow relationships.\n  - name: Playlists\n    description: Routes to manage playlists, their tracks, and collaborators.\n\n\n########## [ROUTES]\npaths:\n  ########## EVENTS\n  /me/events:\n    get:\n      tags:\n        - Events\n      summary: List events for the current user\n      operationId: listCurrentUserEvents\n      description: >\n        Returns the list of events the authenticated user is involved in\n        (as owner or guest).\n      responses:\n        '200':\n          description: List of events for the current user\n          content:\n            application/json:\n              schema:\n                type: array\n                items:\n                  $ref: '#/components/schemas/EventResponse'\n        '401':\n          description: Unauthorized (missing or invalid JWT)\n\n  /events:\n    post:\n      tags:\n        - Events\n      summary: Create a new event\n      operationId: createEvent\n      description: Creates a new event for the authenticated user.\n      requestBody:\n        required: true\n        content:\n          application/json:\n            schema:\n              $ref: '#/components/schemas/CreateEventInput'\n          multipart/form-data:\n            schema:\n              allOf:\n                - $ref: '#/components/schemas/CreateEventInput'\n                - type: object\n                  properties:\n                    image:\n                      type: string\n                      format: binary\n                      description: Optional image file for the event.\n      responses:\n        '201':\n          description: Event created successfully\n          content:\n            application/json:\n              schema:\n                type: object\n                properties:\n                  message:\n                    type: string\n                    example: Event created successfully\n        '400':\n          description: Invalid payload\n        '401':\n          description: Unauthorized (missing or invalid JWT)\n\n  /events/{id}:\n    get:\n      tags:\n        - Events\n      summary: Get event by id\n      operationId: getEventById\n      parameters:\n        - name: id\n          in: path\n          required: true\n          schema:\n            type: string\n          description: The event ID.\n      responses:\n        '200':\n          description: Event details\n          content:\n            application/json:\n              schema:\n                $ref: '#/components/schemas/EventResponse'\n        '401':\n          description: Unauthorized (missing or invalid JWT)\n        '403':\n          description: Forbidden — the event is private and the user is not allowed to view it\n        '404':\n          description: Event not found\n\n    put:\n      tags:\n        - Events\n      summary: Update an existing event\n      operationId: updateEventById\n      parameters:\n        - name: id\n          in: path\n          required: true\n          schema:\n            type: string\n          description: The event ID.\n      requestBody:\n        required: true\n        content:\n          application/json:\n            schema:\n              $ref: '#/components/schemas/UpdateEventInput'\n      responses:\n        '200':\n          description: Event updated successfully\n          content:\n            application/json:\n              schema:\n                type: object\n                properties:\n                  message:\n                    type: string\n                    example: Event updated successfully\n        '400':\n          description: Invalid payload\n        '401':\n          description: Unauthorized\n        '404':\n          description: Event not found\n\n    delete:\n      tags:\n        - Events\n      summary: Delete an event\n      operationId: deleteEventById\n      parameters:\n        - name: id\n          in: path\n          required: true\n          schema:\n            type: string\n          description: The event ID.\n      responses:\n        '204':\n          description: Event deleted successfully (no content)\n        '401':\n          description: Unauthorized\n        '404':\n          description: Event not found\n\n  /events/radar:\n    get:\n      tags:\n        - Events\n      summary: Radar of nearby events\n      operationId: getEventsRadar\n      description: >\n        Returns a list of events located near a given position.\n        Returns only public events (100km arround the given position).\n      parameters:\n        - name: lat\n          in: query\n          required: true\n          description: Latitude of the reference point (decimal degrees).\n          schema:\n            type: number\n            example: 48.8566\n        - name: long\n          in: query\n          required: true\n          description: Longitude of the reference point (decimal degrees).\n          schema:\n            type: number\n            example: 2.3522\n      responses:\n        '200':\n          description: List of events within the requested radius\n          content:\n            application/json:\n              schema:\n                type: array\n                items:\n                  $ref: '#/components/schemas/EventRadarItem'\n        '400':\n          description: Invalid geolocation parameters\n        '401':\n          description: Unauthorized (missing or invalid JWT)\n\n  /events/{id}/start:\n    post:\n      tags:\n        - Events\n      summary: Start an event\n      operationId: startEvent\n      description: Marks the event as started. Only owner can start his event.\n      parameters:\n        - name: id\n          in: path\n          required: true\n          description: The event ID.\n          schema:\n            type: string\n      responses:\n        '200':\n          description: Event successfully started\n          content:\n            application/json:\n              schema:\n                type: object\n                properties:\n                  message:\n                    type: string\n                    example: Event started successfully\n        '401':\n          description: Unauthorized\n        '403':\n          description: Forbidden — user lacks permission to start this event\n        '404':\n          description: Event not found\n\n  /events/{id}/stop:\n    post:\n      tags:\n        - Events\n      summary: Stop an event\n      operationId: stopEvent\n      description: Marks the event as stopped/finished. Only the owner can stop an event.\n      parameters:\n        - name: id\n          in: path\n          required: true\n          description: The event ID.\n          schema:\n            type: string\n      responses:\n        '200':\n          description: Event successfully stopped\n          content:\n            application/json:\n              schema:\n                type: object\n                properties:\n                  message:\n                    type: string\n                    example: Event stopped successfully\n        '401':\n          description: Unauthorized\n        '403':\n          description: Forbidden — user lacks permission to stop this event\n        '404':\n          description: Event not found\n\n  /events/{id}/invite:\n    post:\n      tags:\n        - Events\n      summary: Add a user to an event\n      operationId: inviteUserToEvent\n      description: Adds a user to the event with a given role.\n      parameters:\n        - name: id\n          in: path\n          required: true\n          schema:\n            type: string\n          description: The event ID.\n      requestBody:\n        required: true\n        content:\n          application/json:\n            schema:\n              $ref: '#/components/schemas/EventInvitationInput'\n      responses:\n        '201':\n          description: User successfully added to the event\n          content:\n            application/json:\n              schema:\n                type: object\n                properties:\n                  message:\n                    type: string\n                    example: User invited successfully\n        '400':\n          description: Invalid payload\n        '401':\n          description: Unauthorized\n        '403':\n          description: Forbidden — insufficient permissions\n        '404':\n          description: Event or user not found\n    put:\n      tags:\n        - Events\n      summary: Edit a user role in an event\n      operationId: editEventUser\n      description: Updates the role of a user already participating in the event.\n      parameters:\n        - name: id\n          in: path\n          required: true\n          schema:\n            type: string\n          description: The event ID.\n      requestBody:\n        required: true\n        content:\n          application/json:\n            schema:\n              $ref: '#/components/schemas/EventInvitationInput'\n      responses:\n        '200':\n          description: User role updated\n          content:\n            application/json:\n              schema:\n                type: object\n                properties:\n                  message:\n                    type: string\n                    example: User role updated successfully\n        '400':\n          description: Invalid payload\n        '401':\n          description: Unauthorized\n        '403':\n          description: Forbidden — insufficient permissions\n        '404':\n          description: Event or user not found\n    delete:\n      tags:\n        - Events\n      summary: Remove a user from an event\n      operationId: removeUserFromEvent\n      description: Removes a user from the event.\n      parameters:\n        - name: id\n          in: path\n          required: true\n          schema:\n            type: string\n          description: The event ID.\n      requestBody:\n        required: true\n        content:\n          application/json:\n            schema:\n              type: object\n              required:\n                - user_id\n              properties:\n                user_id:\n                  type: string\n                  example: \"c4e6b690-bbf2-4068-8d18-316cc468fbab\"\n                  description: ID of the user to remove.\n      responses:\n        '204':\n          description: User removed (no content)\n        '400':\n          description: Invalid payload\n        '401':\n          description: Unauthorized\n        '403':\n          description: Forbidden — insufficient permissions\n        '404':\n          description: Event or user not found\n\n\n  ########### SEARCH\n  /search:\n    get:\n      tags:\n        - Search\n      summary: Search tracks, playlists, users, and events\n      operationId: search\n      description: >\n        Global search endpoint. Depending on the \"type\" parameter, it searches\n        among tracks (Spotify), playlists, users, and/or events.\n        The 'all' type option exclude tracks.\n      parameters:\n        - name: q\n          in: query\n          required: true\n          description: Search query string.\n          schema:\n            type: string\n            example: \"jazz\"\n        - name: type\n          in: query\n          required: true\n          description: >\n            Type of resources to search. Use \"all\" to search across all supported types.\n          schema:\n            type: string\n            enum:\n              - track\n              - playlist\n              - user\n              - event\n              - all\n            example: \"all\"\n        - name: limit\n          in: query\n          required: false\n          description: Maximum number of items to return per category.\n          schema:\n            type: integer\n            minimum: 1\n            example: 20\n        - name: offset\n          in: query\n          required: false\n          description: Offset for pagination (number of items to skip).\n          schema:\n            type: integer\n            minimum: 0\n            example: 0\n      responses:\n        '200':\n          description: Search results grouped by resource type\n          content:\n            application/json:\n              schema:\n                $ref: '#/components/schemas/SearchResponse'\n        '400':\n          description: Missing or invalid query parameters (e.g. \"q\" or \"type\")\n        '401':\n          description: Unauthorized (missing or invalid JWT)\n        '500':\n          description: Unexpected error from Spotify or database\n\n\n  ########### PROFILE\n  /me/profile:\n    get:\n      tags:\n        - Profile\n      summary: Get the authenticated user's profile\n      operationId: getCurrentUserProfile\n      description: >\n        Returns the profile of the currently authenticated user.\n      responses:\n        '200':\n          description: The authenticated user's profile\n          content:\n            application/json:\n              schema:\n                $ref: '#/components/schemas/CurrentUserProfileResponse'\n        '401':\n          description: Unauthorized (missing or invalid JWT)\n        '404':\n          description: Profile not found\n\n  /profile/user/{userId}:\n    get:\n      tags:\n        - Profile\n      summary: Get public profile for a user\n      operationId: getUserProfile\n      description: >\n        Returns the public profile of the specified user.  \n        If the requester is authenticated, the response also includes\n        follow relationship flags (is_following, is_follower, is_friend)\n        relative to the current user.\n      parameters:\n        - name: userId\n          in: path\n          required: true\n          description: ID of the user whose profile is requested.\n          schema:\n            type: string\n      responses:\n        '200':\n          description: Public profile information for the requested user\n          content:\n            application/json:\n              schema:\n                $ref: '#/components/schemas/ProfileWithFollowInfo'\n        '401':\n          description: Unauthorized (missing or invalid JWT)\n        '404':\n          description: Profile not found\n\n  /profile/update:\n    put:\n      tags:\n        - Profile\n      summary: Update current user profile\n      operationId: updateCurrentUserProfile\n      description: >\n        Updates the authenticated user's profile.  \n        Only the provided fields are updated; all fields are optional.\n      requestBody:\n        required: true\n        content:\n          application/json:\n            schema:\n              $ref: '#/components/schemas/UpdateProfileInput'\n      responses:\n        '200':\n          description: Updated profile of the current user\n          content:\n            application/json:\n              schema:\n                $ref: '#/components/schemas/FullProfileResponse'\n        '400':\n          description: Invalid payload (validation failed)\n        '401':\n          description: Unauthorized (missing or invalid JWT)\n        '500':\n          description: Failed to update profile\n\n  /profile/follows/{userId}:\n    get:\n      tags:\n        - Profile\n      summary: Get followers and following for a user\n      operationId: getUserFollows\n      description: >\n        Returns the list of followers and following profiles for the given user.\n      parameters:\n        - name: userId\n          in: path\n          required: true\n          description: ID of the user whose follow relationships are requested.\n          schema:\n            type: string\n      responses:\n        '200':\n          description: Followers and following profiles for the user\n          content:\n            application/json:\n              schema:\n                $ref: '#/components/schemas/FollowsResponse'\n        '401':\n          description: Unauthorized (missing or invalid JWT)\n        '404':\n          description: User not found\n\n  /profile/follow/{userId}:\n    post:\n      tags:\n        - Profile\n      summary: Follow a user\n      operationId: followUser\n      description: >\n        Creates a follow relationship from the authenticated user to the given user.\n      parameters:\n        - name: userId\n          in: path\n          required: true\n          description: ID of the user to follow.\n          schema:\n            type: string\n      responses:\n        '200':\n          description: Follow operation successful\n          content:\n            application/json:\n              schema:\n                $ref: '#/components/schemas/FollowActionResponse'\n        '400':\n          description: Invalid follow action (e.g. following yourself or already following)\n        '401':\n          description: Unauthorized (missing or invalid JWT)\n        '404':\n          description: User not found\n        '409':\n          description: Error Conflict (the relationship exist already)\n\n    delete:\n      tags:\n        - Profile\n      summary: Unfollow a user\n      operationId: unfollowUser\n      description: >\n        Removes the follow relationship from the authenticated user to the given user.\n      parameters:\n        - name: userId\n          in: path\n          required: true\n          description: ID of the user to unfollow.\n          schema:\n            type: string\n      responses:\n        '200':\n          description: Unfollow operation successful\n          content:\n            application/json:\n              schema:\n                $ref: '#/components/schemas/FollowActionResponse'\n        '400':\n          description: Invalid unfollow action\n        '401':\n          description: Unauthorized (missing or invalid JWT)\n        '404':\n          description: User not found\n\n\n  ########## PLAYLISTS\n  /me/playlists:\n    get:\n      tags:\n        - Playlists\n      summary: Get playlists of the authenticated user\n      operationId: getCurrentUserPlaylists\n      description: >\n        Returns all playlists the authenticated user owns, collaborates on\n        or can invite from, including owner information and the user's role.\n      responses:\n        '200':\n          description: List of playlists for the authenticated user\n          content:\n            application/json:\n              schema:\n                $ref: '#/components/schemas/CurrentUserPlaylistsResponse'\n        '401':\n          description: Unauthorized (missing or invalid JWT)\n\n  /playlists:\n    post:\n      tags:\n        - Playlists\n      summary: Create a new playlist\n      operationId: createPlaylist\n      description: >\n        Creates a new playlist for the authenticated user.\n        Requires a valid subscription (enforced by middleware).\n      requestBody:\n        required: true\n        content:\n          application/json:\n            schema:\n              $ref: '#/components/schemas/CreatePlaylistInput'\n      responses:\n        '201':\n          description: Playlist created successfully\n          content:\n            application/json:\n              schema:\n                $ref: '#/components/schemas/PlaylistResponse'\n        '400':\n          description: Invalid payload (validation failed)\n        '401':\n          description: Unauthorized (missing or invalid JWT)\n        '402':\n          description: Payment required (no active premium subscription)\n        '500':\n          description: Failed to create playlist\n\n  /playlists/{id}:\n    get:\n      tags:\n        - Playlists\n      summary: Get playlist details with tracks\n      operationId: getPlaylistById\n      description: >\n        Returns full playlist details for the given ID, including tracks\n        enriched with Spotify metadata, collaborators, members and\n        user-specific permissions.\n      parameters:\n        - name: id\n          in: path\n          required: true\n          description: ID of the playlist.\n          schema:\n            type: string\n      responses:\n        '200':\n          description: Playlist details\n          content:\n            application/json:\n              schema:\n                $ref: '#/components/schemas/PlaylistDetailsResponse'\n        '401':\n          description: >\n            Unauthorized, missing JWT or Spotify account not connected.\n        '403':\n          description: Access forbidden (private playlist without permission)\n        '404':\n          description: Playlist not found\n\n    put:\n      tags:\n        - Playlists\n      summary: Update a playlist\n      operationId: updatePlaylist\n      description: >\n        Updates basic metadata of a playlist. Only the owner or users with\n        appropriate permissions can update it.\n      parameters:\n        - name: id\n          in: path\n          required: true\n          description: ID of the playlist.\n          schema:\n            type: string\n      requestBody:\n        required: true\n        content:\n          application/json:\n            schema:\n              $ref: '#/components/schemas/UpdatePlaylistInput'\n      responses:\n        '200':\n          description: Playlist updated successfully\n          content:\n            application/json:\n              schema:\n                type: object\n                properties:\n                  message:\n                    type: string\n                    example: \"Playlist updated successfully\"\n        '400':\n          description: Invalid payload\n        '401':\n          description: Unauthorized\n        '403':\n          description: Forbidden (user lacks permission)\n        '404':\n          description: Playlist not found\n    delete:\n      tags:\n        - Playlists\n      summary: Delete a playlist\n      operationId: deletePlaylist\n      description: >\n        Deletes a playlist. Only the owner (or roles allowed by permissions)\n        can delete the playlist.\n      parameters:\n        - name: id\n          in: path\n          required: true\n          description: ID of the playlist.\n          schema:\n            type: string\n      responses:\n        '200':\n          description: Playlist deleted successfully\n          content:\n            application/json:\n              schema:\n                type: object\n                properties:\n                  message:\n                    type: string\n                    example: \"Playlist deleted successfully\"\n        '401':\n          description: Unauthorized\n        '403':\n          description: Forbidden (user lacks permission)\n        '404':\n          description: Playlist not found\n\n  /playlists/{id}/tracks:\n    post:\n      tags:\n        - Playlists\n      summary: Add tracks to a playlist\n      operationId: addTracksToPlaylist\n      description: >\n        Adds one or more tracks to the specified playlist. Requires the\n        ADD_SONG permission on that playlist.\n      parameters:\n        - name: id\n          in: path\n          required: true\n          description: ID of the playlist.\n          schema:\n            type: string\n      requestBody:\n        required: true\n        content:\n          application/json:\n            schema:\n              $ref: '#/components/schemas/PlaylistTracksInput'\n      responses:\n        '201':\n          description: Tracks added successfully\n          content:\n            application/json:\n              schema:\n                type: object\n                properties:\n                  message:\n                    type: string\n                    example: \"Tracks added successfully\"\n        '400':\n          description: Invalid payload (uris must be an array of strings)\n        '401':\n          description: Unauthorized (missing or invalid JWT)\n        '403':\n          description: Forbidden (user has no permission to add songs)\n        '404':\n          description: Playlist not found\n\n    delete:\n      tags:\n        - Playlists\n      summary: Remove tracks from a playlist\n      operationId: removeTracksFromPlaylist\n      description: >\n        Removes one or more tracks from the specified playlist. Requires the\n        DELETE_SONG permission on that playlist.\n      parameters:\n        - name: id\n          in: path\n          required: true\n          description: ID of the playlist.\n          schema:\n            type: string\n      requestBody:\n        required: true\n        content:\n          application/json:\n            schema:\n              $ref: '#/components/schemas/PlaylistTracksInput'\n      responses:\n        '200':\n          description: Tracks removed successfully\n          content:\n            application/json:\n              schema:\n                type: object\n                properties:\n                  message:\n                    type: string\n                    example: \"Tracks deleted successfully\"\n        '400':\n          description: Invalid payload (uris must be an array of strings)\n        '401':\n          description: Unauthorized (missing or invalid JWT)\n        '403':\n          description: Forbidden (user has no permission to delete songs)\n        '404':\n          description: Playlist not found\n\n  /playlists/{id}/users:\n    post:\n      tags:\n        - Playlists\n      summary: Add a user to a playlist\n      operationId: addUserToPlaylist\n      description: >\n        Adds a user to the playlist as a member or collaborator. Requires the\n        ADD_USER permission on that playlist.\n      parameters:\n        - name: id\n          in: path\n          required: true\n          description: ID of the playlist.\n          schema:\n            type: string\n      requestBody:\n        required: true\n        content:\n          application/json:\n            schema:\n              $ref: '#/components/schemas/PlaylistUserInput'\n      responses:\n        '200':\n          description: User added to playlist successfully\n          content:\n            application/json:\n              schema:\n                type: object\n                properties:\n                  message:\n                    type: string\n                    example: \"User added successfully as collaborator\"\n        '400':\n          description: Invalid payload (missing or invalid user_id / role)\n        '401':\n          description: Unauthorized (missing or invalid JWT)\n        '403':\n          description: Forbidden (user has no permission to add users)\n        '404':\n          description: Playlist or user not found\n        '409':\n          description: Error conflict, user already into playlist members\n\n    delete:\n      tags:\n        - Playlists\n      summary: Remove a user from a playlist\n      operationId: removeUserFromPlaylist\n      description: >\n        Removes a user from the playlist. A user may remove themselves. Removing\n        another user requires the REMOVE_USER permission.\n      parameters:\n        - name: id\n          in: path\n          required: true\n          description: ID of the playlist.\n          schema:\n            type: string\n      requestBody:\n        required: true\n        content:\n          application/json:\n            schema:\n              $ref: '#/components/schemas/PlaylistUserInput'\n      responses:\n        '200':\n          description: User removed from playlist successfully\n          content:\n            application/json:\n              schema:\n                type: object\n                properties:\n                  message:\n                    type: string\n                    example: \"User removed successfully from playlist\"\n        '400':\n          description: Invalid payload (missing or invalid user_id / role)\n        '401':\n          description: Unauthorized (missing or invalid JWT)\n        '403':\n          description: Forbidden (user has no permission to remove others)\n        '404':\n          description: Playlist or user not found\n\n\n########## [SCHEMAS]\ncomponents:\n  securitySchemes:\n    bearerAuth:\n      type: http\n      scheme: bearer\n      bearerFormat: JWT\n\n  schemas:\n    Event:\n      type: object\n      required:\n        - id\n        - name\n        - is_private\n        - everyone_can_vote\n        - playlistId\n        - beginning_at\n        - spatio_licence\n        - done\n      properties:\n        id:\n          type: string\n          example: \"ac4f0cd4-197e-443c-b9ff-8b9873dad829\"\n        name:\n          type: string\n          example: \"Jazz Night\"\n        image_url:\n          type: string\n          format: uri\n          nullable: true\n          example: \"https://example.com/event.jpg\"\n        is_private:\n          type: boolean\n          example: false\n        everyone_can_vote:\n          type: boolean\n          example: true\n        description:\n          type: string\n          nullable: true\n          example: \"An evening to discover local artists.\"\n        playlist_id:\n          type: string\n          nullable: true\n          example: \"pl_abc\"\n        playlistId:\n          type: string\n          example: \"pl_abc\"\n        beginning_at:\n          type: string\n          format: date-time\n          example: \"2025-01-10T20:00:00Z\"\n        spatio_licence:\n          type: boolean\n          example: true\n        done:\n          type: boolean\n          example: false\n\n    Owner:\n      type: object\n      properties:\n        id:\n          type: string\n        username:\n          type: string\n        avatar_url:\n          type: string\n          nullable: true\n\n    EventUserPermissions:\n      type: object\n      properties:\n        role:\n          type: string\n          example: owner\n        can_edit:\n          type: boolean\n        can_delete:\n          type: boolean\n        can_invite:\n          type: boolean\n        can_vote:\n          type: boolean\n\n    EventMember:\n      type: object\n      properties:\n        profile:\n          type: object\n          properties:\n            id:\n              type: string\n            username:\n              type: string\n            avatar_url:\n              type: string\n              nullable: true\n        role:\n          type: string\n          example: voter\n\n    EventResponse:\n      type: object\n      properties:\n        event:\n          $ref: '#/components/schemas/Event'\n        owner:\n          $ref: '#/components/schemas/Owner'\n        user:\n          $ref: '#/components/schemas/EventUserPermissions'\n        members:\n          type: array\n          items:\n            $ref: '#/components/schemas/EventMember'\n\n    Location:\n      type: object\n      properties:\n        coordinates:\n          type: object\n          properties:\n            lat:\n              type: number\n              example: 37.42221\n            long:\n              type: number\n              example: -122.0853\n        city:\n          type: string\n          nullable: true\n          example: \"Mountain View\"\n        address:\n          type: string\n          nullable: true\n          example: \"160 Castro St\"\n        country:\n          type: string\n          nullable: true\n          example: \"USA\"\n        venuename:\n          type: string\n          nullable: true\n          example: \"Doppio Zero\"\n        complement:\n          type: string\n          nullable: true\n          example: \"CA 94041\"\n      required:\n        - coordinates\n\n    CreateEventInput:\n      type: object\n      required:\n        - name\n        - is_private\n        - everyone_can_vote\n        - playlist_id\n        - beginning_at\n        - spatio_licence\n        - location\n      properties:\n        name:\n          type: string\n          example: \"Jazz Night\"\n        description:\n          type: string\n          nullable: true\n          example: \"An evening to discover local artists.\"\n        is_private:\n          type: boolean\n          example: false\n        everyone_can_vote:\n          type: boolean\n          example: true\n        playlist_id:\n          type: string\n          description: ID of the associated playlist\n          example: \"pl_abc\"\n        beginning_at:\n          type: string\n          format: date-time\n          example: \"2025-01-10T20:00:00Z\"\n        spatio_licence:\n          type: boolean\n          example: true\n        location:\n          $ref: '#/components/schemas/Location'\n\n    UpdateEventInput:\n      type: object\n      description: >\n        Fields to update on an existing event.\n        All properties are optional; only provided fields will be updated.\n      properties:\n        name:\n          type: string\n          example: \"Updated Jazz Night\"\n        description:\n          type: string\n          nullable: true\n        is_private:\n          type: boolean\n        everyone_can_vote:\n          type: boolean\n        playlist_id:\n          type: string\n          description: ID of the associated playlist\n        beginning_at:\n          type: string\n          format: date-time\n        spatio_licence:\n          type: boolean\n        location:\n          $ref: '#/components/schemas/Location'\n\n    EventRadarItem:\n      type: object\n      description: \"Simplified representation of an event for proximity radar results.\"\n      properties:\n        id:\n          type: string\n          example: \"ac4f0cd4-197e-443c-b9ff-8b9873dad829\"\n        name:\n          type: string\n          example: \"Jazz Night\"\n        beginning_at:\n          type: string\n          format: date-time\n          example: \"2025-01-10T20:00:00Z\"\n        image_url:\n          type: string\n          format: uri\n          nullable: true\n          example: \"https://example.com/event.jpg\"\n        owner_id:\n          type: string\n          example: \"c4e6b690-bbf2-4068-8d18-316cc468fbab\"\n        owner_name:\n          type: string\n          example: \"Alice\"\n        owner_avatar_url:\n          type: string\n          format: uri\n          nullable: true\n          example: \"https://example.com/avatar.jpg\"\n        long:\n          type: number\n          example: 2.3522\n        lat:\n          type: number\n          example: 48.8566\n        dist_meters:\n          type: number\n          description: Distance from the user to the event (in meters).\n          example: 1342.5\n        done:\n          type: boolean\n          description: Whether the event is finished.\n          example: false\n        spatio_licence:\n          type: boolean\n          description: Whether GPS position is required for voting.\n          example: true\n\n    EventInvitationInput:\n      type: object\n      required:\n        - user_id\n        - role\n      properties:\n        user_id:\n          type: string\n          example: \"c4e6b690-bbf2-4068-8d18-316cc468fbab\"\n        role:\n          type: string\n          description: Role assigned to the user.\n          enum:\n            - inviter\n            - voter\n            - member\n            - collaborator\n          example: \"voter\"\n\n    ProfileResponse:\n      type: object\n      description: Basic public profile information.\n      properties:\n        id:\n          type: string\n          example: \"5c8ac14c-7272-487b-945a-5752b3810322\"\n        username:\n          type: string\n          example: \"susan\"\n        email:\n          type: string\n          format: email\n          example: \"susan@example.com\"\n        avatar_url:\n          type: string\n          format: uri\n          nullable: true\n          example: \"https://example.com/avatar.jpg\"\n        bio:\n          type: string\n          nullable: true\n          example: \"Music lover and vinyl collector.\"\n        music_genre:\n          type: string\n          nullable: true\n          example: \"jazz\"\n\n    ProfileWithFollowInfo:\n      type: object\n      description: Profile information augmented with relationship flags.\n      allOf:\n        - $ref: '#/components/schemas/ProfileResponse'\n        - type: object\n          properties:\n            is_following:\n              type: boolean\n              description: Whether the current user is following this profile.\n              example: true\n            is_follower:\n              type: boolean\n              description: Whether this profile is following the current user.\n              example: false\n            is_friend:\n              type: boolean\n              description: True if both users follow each other.\n              example: false\n\n    PlaylistResponse:\n      type: object\n      description: Public playlist returned in search results.\n      properties:\n        id:\n          type: string\n          example: \"pl_abc\"\n        name:\n          type: string\n          example: \"Jazz Classics\"\n        description:\n          type: string\n          nullable: true\n          example: \"All-time favorite jazz tracks.\"\n        is_private:\n          type: boolean\n          example: false\n        is_collaborative:\n          type: boolean\n          example: true\n        cover_url:\n          type: string\n          format: uri\n          nullable: true\n          example: \"https://example.com/playlist-cover.jpg\"\n        created_at:\n          type: string\n          format: date-time\n        updated_at:\n          type: string\n          format: date-time\n        owner_id:\n          type: string\n          example: \"user_123\"\n        is_spotify_sync:\n          type: boolean\n          nullable: true\n          description: Whether the playlist is synced with Spotify.\n        spotify_id:\n          type: string\n          nullable: true\n          example: \"37i9dQZF1DXbITWG1ZJKYt\"\n        owner:\n          $ref: '#/components/schemas/ProfileResponse'\n\n    EventResponseReduced:\n      type: object\n      description: Reduced event representation for search results.\n      properties:\n        event:\n          $ref: '#/components/schemas/Event'\n        owner:\n          $ref: '#/components/schemas/Owner'\n\n    TrackResponse:\n      type: object\n      description: >\n        Track object returned by the internal mapping of Spotify search results.\n      additionalProperties: true\n\n    SearchResponse:\n      type: object\n      description: Search results grouped by resource type.\n      properties:\n        trackResults:\n          type: array\n          items:\n            $ref: '#/components/schemas/TrackResponse'\n        playlistResults:\n          type: array\n          items:\n            $ref: '#/components/schemas/PlaylistResponse'\n        userResults:\n          type: array\n          items:\n            $ref: '#/components/schemas/ProfileWithFollowInfo'\n        eventResults:\n          type: array\n          items:\n            $ref: '#/components/schemas/EventResponseReduced'\n\n    CurrentUserProfileResponse:\n      description: >\n        Enriched profile for the currently authenticated user,\n        including follow relationships and Spotify connection status.\n      allOf:\n        - $ref: '#/components/schemas/ProfileResponse'\n        - type: object\n          properties:\n            is_connected_to_spotify:\n              type: boolean\n              description: True if the user has linked a Spotify account.\n              example: true\n            followers:\n              type: array\n              description: Users who follow the current user.\n              items:\n                $ref: '#/components/schemas/FollowUserWithRelation'\n            following:\n              type: array\n              description: Users that the current user is following.\n              items:\n                $ref: '#/components/schemas/FollowUserWithRelation'\n          required:\n            - is_connected_to_spotify\n            - followers\n            - following\n\n    UpdateProfileInput:\n      type: object\n      description: >\n        Payload for updating the authenticated user's profile.\n        All properties are optional, so only provided fields will be updated.\n      properties:\n        username:\n          type: string\n          example: \"darwin\"\n        email:\n          type: string\n          format: email\n          example: \"darwin@lovefish.com\"\n        avatar_url:\n          type: string\n          format: uri\n          nullable: true\n          example: \"https://lovefish/avatar.jpg\"\n        bio:\n          type: string\n          nullable: true\n          example: \"Fish music lover and clams vinyl collector.\"\n        music_genre:\n          type: array\n          items:\n            type: string\n          nullable: true\n          description: >\n            List of preferred music genres (e.g. [\"jazz\", \"blues\"]) or null.\n        privacy_setting:\n          type: string\n          description: Privacy level of the profile.\n          enum:\n            - public\n            - friends\n            - private\n          example: \"public\"\n\n    FullProfileResponse:\n      type: object\n      description: Full profile returned after update, including Spotify authentication fields.\n      properties:\n        id:\n          type: string\n          example: \"dc8405bf-df39-4ae2-9b20-ee3175835bf1\"\n        username:\n          type: string\n          example: \"Gumball\"\n        email:\n          type: string\n          format: email\n          example: \"gum@gum.gum\"\n        avatar_url:\n          type: string\n          format: uri\n          nullable: true\n          example: \"https://example.com/avatar.jpg\"\n        bio:\n          type: string\n          nullable: true\n          example: \"Electro music fanatic.\"\n        music_genre:\n          type: array\n          items:\n            type: string\n          nullable: true\n          example: [\"electronic\", \"funk\"]\n        privacy_setting:\n          type: string\n          enum: [public, friends, private]\n          example: public\n\n        # Spotify fields\n        spotify_access_token:\n          type: string\n          description: Spotify OAuth access token\n          example: \"BQD3xJf...\"\n        spotify_refresh_token:\n          type: string\n          description: Spotify OAuth refresh token\n          example: \"AQDFkj...\"\n        spotify_token_expires_at:\n          type: string\n          format: date-time\n          description: Expiration timestamp of the Spotify token\n          example: \"2025-12-08T08:06:28.882Z\"\n\n      required:\n        - id\n        - username\n        - email\n        - privacy_setting\n\n    FollowActionResponse:\n      type: object\n      description: Generic response for follow/unfollow operations.\n      properties:\n        success:\n          type: boolean\n          example: true\n      required:\n        - success\n\n    FollowsResponse:\n      type: object\n      description: Followers and following lists for a given user.\n      properties:\n        followers:\n          type: array\n          description: Users who follow the requested user.\n          items:\n            $ref: '#/components/schemas/FollowUserWithRelation'\n        following:\n          type: array\n          description: Users that the requested user is following.\n          items:\n            $ref: '#/components/schemas/FollowUserWithRelation'\n      required:\n        - followers\n        - following\n\n    FollowUserWithRelation:\n      type: object\n      description: >\n        Lightweight profile used in followers/following lists, including\n        relationship flags relative to the authenticated user.\n      properties:\n        id:\n          type: string\n          example: \"9f6e5ad2-b7cc-4286-bc32-9f8ca76dc3cf\"\n        username:\n          type: string\n          example: \"Victor\"\n        created_at:\n          type: string\n          format: date-time\n          description: When this follow relationship was created.\n          example: \"2025-12-08T08:31:16.923672+00:00\"\n        is_follower:\n          type: boolean\n          description: >\n            True if this user follows the authenticated user.\n          example: false\n        is_following:\n          type: boolean\n          description: >\n            True if the authenticated user follows this user.\n          example: false\n        is_friend:\n          type: boolean\n          description: >\n            True if both users follow each other (mutual follow).\n          example: false\n      required:\n        - id\n        - username\n        - created_at\n        - is_follower\n        - is_following\n        - is_friend\n\n    CreatePlaylistInput:\n      type: object\n      description: Payload to create a new playlist.\n      required:\n        - name\n      properties:\n        name:\n          type: string\n          minLength: 1\n          maxLength: 255\n          example: \"My Roadtrip Playlist\"\n        description:\n          type: string\n          nullable: true\n          example: \"Songs for long drives.\"\n        cover_url:\n          type: string\n          format: uri\n          nullable: true\n          example: \"https://example.com/playlist-cover.jpg\"\n        is_private:\n          type: boolean\n          description: Whether the playlist is private.\n          default: false\n          example: false\n        is_collaborative:\n          type: boolean\n          description: Whether other users can collaborate on the playlist.\n          default: false\n          example: true\n\n    UpdatePlaylistInput:\n      type: object\n      description: >\n        Fields to update on an existing playlist. All properties are optional;\n        only provided fields will be updated.\n      properties:\n        name:\n          type: string\n          minLength: 3\n          maxLength: 255\n          example: \"Updated Playlist Name\"\n        description:\n          type: string\n          nullable: true\n          example: \"Updated description.\"\n        cover_url:\n          type: string\n          format: uri\n          nullable: true\n          example: \"https://example.com/new-cover.jpg\"\n        is_private:\n          type: boolean\n          description: Whether the playlist is private.\n          example: true\n        is_collaborative:\n          type: boolean\n          description: Whether other users can collaborate on the playlist.\n          example: false\n\n    PlaylistUserPermissions:\n      type: object\n      description: Permissions of the current user on this playlist.\n      properties:\n        can_edit:\n          type: boolean\n          example: true\n        can_invite:\n          type: boolean\n          example: true\n        is_following:\n          type: boolean\n          example: true\n        role:\n          type: string\n          description: Role of the user relative to the playlist.\n          enum:\n            - owner\n            - collaborator\n            - member\n            - none\n          example: \"owner\"\n      required:\n        - can_edit\n        - can_invite\n        - is_following\n        - role\n\n    SpotifyTrackArtist:\n      type: object\n      properties:\n        name:\n          type: string\n          example: \"Miles Davis\"\n\n    SpotifyTrackAlbumImage:\n      type: object\n      properties:\n        url:\n          type: string\n          format: uri\n          example: \"https://i.scdn.co/image/abc123\"\n\n    SpotifyTrackAlbum:\n      type: object\n      properties:\n        name:\n          type: string\n          example: \"Kind of Blue\"\n        images:\n          type: array\n          items:\n            $ref: '#/components/schemas/SpotifyTrackAlbumImage'\n\n    SpotifyTrackDetails:\n      type: object\n      description: Minimal Spotify track information attached to a playlist track.\n      properties:\n        id:\n          type: string\n          example: \"3Zwu2K0Qa5sT6teCCHPShP\"\n        name:\n          type: string\n          example: \"So What\"\n        artists:\n          type: array\n          items:\n            $ref: '#/components/schemas/SpotifyTrackArtist'\n        album:\n          $ref: '#/components/schemas/SpotifyTrackAlbum'\n        duration_ms:\n          type: integer\n          example: 545000\n        uri:\n          type: string\n          example: \"spotify:track:3Zwu2K0Qa5sT6teCCHPShP\"\n\n    PlaylistTrackWithDetails:\n      type: object\n      description: >\n        Track entry in a playlist, including internal metadata and optional\n        Spotify details.\n      properties:\n        id:\n          type: string\n          example: \"plt_track_123\"\n        playlist_id:\n          type: string\n          example: \"pl_abc\"\n        track_id:\n          type: string\n          description: Spotify track ID or URI used as foreign key.\n          example: \"3Zwu2K0Qa5sT6teCCHPShP\"\n        added_at:\n          type: string\n          format: date-time\n          example: \"2025-12-08T09:00:00Z\"\n        added_by:\n          type: string\n          description: ID of the user who added the track.\n          example: \"user_123\"\n        details:\n          $ref: '#/components/schemas/SpotifyTrackDetails'\n      required:\n        - id\n        - playlist_id\n        - track_id\n        - added_at\n        - added_by\n\n    PlaylistCollaborator:\n      type: object\n      description: Collaborator entry for a playlist.\n      properties:\n        id:\n          type: string\n          example: \"pl_collab_123\"\n        playlist_id:\n          type: string\n          example: \"pl_abc\"\n        user_id:\n          type: string\n          example: \"user_456\"\n        added_at:\n          type: string\n          format: date-time\n          example: \"2025-12-08T09:05:00Z\"\n        added_by:\n          type: string\n          example: \"user_123\"\n        role:\n          type: string\n          enum:\n            - collaborator\n            - owner\n          example: \"collaborator\"\n      required:\n        - id\n        - playlist_id\n        - user_id\n        - added_at\n        - added_by\n        - role\n\n    PlaylistMember:\n      type: object\n      description: Member entry for a playlist (non-collaborator).\n      properties:\n        id:\n          type: string\n          example: \"pl_member_123\"\n        playlist_id:\n          type: string\n          example: \"pl_abc\"\n        user_id:\n          type: string\n          example: \"user_789\"\n        added_at:\n          type: string\n          format: date-time\n          example: \"2025-12-08T09:10:00Z\"\n        added_by:\n          type: string\n          example: \"user_123\"\n      required:\n        - id\n        - playlist_id\n        - user_id\n        - added_at\n        - added_by\n\n    PlaylistDetailsResponse:\n      description: >\n        Full playlist details including tracks, membership and user permissions.\n      allOf:\n        - $ref: '#/components/schemas/PlaylistResponse'\n        - type: object\n          properties:\n            tracks:\n              type: array\n              items:\n                $ref: '#/components/schemas/PlaylistTrackWithDetails'\n            collaborators:\n              type: array\n              items:\n                $ref: '#/components/schemas/PlaylistCollaborator'\n            members:\n              type: array\n              items:\n                $ref: '#/components/schemas/PlaylistMember'\n            user:\n              $ref: '#/components/schemas/PlaylistUserPermissions'\n\n    PlaylistTracksInput:\n      type: object\n      description: List of track URIs (or IDs) to add or remove from the playlist.\n      required:\n        - uris\n      properties:\n        uris:\n          type: array\n          items:\n            type: string\n          example:\n            - \"spotify:track:3Zwu2K0Qa5sT6teCCHPShP\"\n            - \"spotify:track:6rqhFgbbKwnb9MLmUQDhG6\"\n\n    PlaylistUserInput:\n      type: object\n      description: >\n        User to add to or remove from the playlist. Role is optional and\n        can be \"member\" or \"collaborator\".\n      required:\n        - user_id\n      properties:\n        user_id:\n          type: string\n          description: ID of the user to add/remove.\n          example: \"dc8405bf-df39-4ae2-9b20-ee3175835bf1\"\n        role:\n          type: string\n          nullable: true\n          description: Role of the user in the playlist (if provided).\n          enum:\n            - member\n            - collaborator\n          example: \"collaborator\"\n\n    CurrentUserPlaylistsResponse:\n      type: array\n      items:\n        $ref: '#/components/schemas/CurrentUserPlaylistItem'\n\n    CurrentUserPlaylistItem:\n      type: object\n      description: >\n        Playlist entry returned by /me/playlists, including owner info\n        and the current user's role on that playlist.\n      properties:\n        id:\n          type: string\n          example: \"1a5e3b72-6717-4f9a-8c2b-b26e6c237120\"\n        name:\n          type: string\n          example: \"BUNNY Playlist\"\n        description:\n          type: string\n          nullable: true\n          example: \"Songs for bunnies.\"\n        owner_id:\n          type: string\n          example: \"dc8405bf-df39-4ae2-9b20-ee3175835bf1\"\n        is_private:\n          type: boolean\n          example: false\n        is_collaborative:\n          type: boolean\n          example: true\n        can_invite:\n          type: boolean\n          description: Whether the current user can invite other users to this playlist.\n          example: true\n        cover_url:\n          type: string\n          format: uri\n          nullable: true\n          example: \"http://image/7797987/...\"\n        created_at:\n          type: string\n          format: date-time\n          example: \"2025-12-08T10:36:28.851462+00:00\"\n        updated_at:\n          type: string\n          format: date-time\n          example: \"2025-12-08T10:44:02.482782+00:00\"\n\n        owner_username:\n          type: string\n          example: \"Squirrel2\"\n        owner_email:\n          type: string\n          format: email\n          example: \"sq@sq.sq\"\n        owner_avatar_url:\n          type: string\n          format: uri\n          nullable: true\n          example: \"https://.../avatars/profiles/1764755716495.jpeg\"\n        owner_bio:\n          type: string\n          nullable: true\n          example: \"Music lover and vinyl collector.\"\n\n        user_role:\n          type: string\n          description: Role of the current user on this playlist.\n          enum:\n            - owner\n            - collaborator\n            - member\n          example: \"owner\"\n      required:\n        - id\n        - name\n        - owner_id\n        - is_private\n        - is_collaborative\n        - can_invite\n        - created_at\n        - updated_at\n        - owner_username\n        - owner_email\n        - user_role\n" as string;
